#include <bits/stdc++.h>
using namespace std;

int main(){
    int x,a;
    char c;
    cin>>x>>c;
    a=a+8;
    if (x>1000){
        a=a+(x-1000)/500*4;
        if (x%500!=0){
            a=a+4;
        }
    }
    if (c=='y'){
        a=a+5;
    }
    cout<<a<<endl;
    return 0;
}
